export function getV3GroupBySlug(slug: string): V3Group | undefined {
  return v3GroupsBySlug[slug];
}

export function getV3SubgroupMapByGroupSlug(groupSlug: string): V3SubgroupMap {
  return v3SubgroupsByGroupSlug[groupSlug] ?? {};
}

export function getV3SubgroupBySlugs(groupSlug: string, subgroupSlug: string): V3Subgroup | undefined {
  const subgroups = getV3SubgroupMapByGroupSlug(groupSlug);
  return subgroups[subgroupSlug];
}
